import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"奠基内功","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/武学基础/奠基内功.md","filePath":"4.资源分区/6.技艺及称号/武技类/武学基础/奠基内功.md"}'),p={name:"4.资源分区/6.技艺及称号/武技类/武学基础/奠基内功.md"};function d(_,e,l,i,c,h){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"奠基内功",tabindex:"-1"},[n("奠基内功 "),a("a",{class:"header-anchor",href:"#奠基内功","aria-label":'Permalink to "奠基内功"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="奠基内功-1" tabindex="-1">奠基内功 <a class="header-anchor" href="#奠基内功-1" aria-label="Permalink to &quot;奠基内功&quot;">​</a></h1><p>奠基内功<br> D+750<br> 注：此技艺遵循【武学总纲】</p><p>内功，命之基、法之始也，修习武道一如登山攀岳，道阻且艰，若根基虚浮、力无着处，则必至祸处、步步危急，唯有扎实命基，以滴水穿石之志练就雄浑沛然之功，方能有所成就。此奠基一法基于此理，不以功效见长，日久方成，授与武君，望诸位，武途顺利。</p><p>炼精化气：以精血意志为引，激发浑身精气，勾连循环，开辟气海丹田。修习者将练就第一缕【内力】（即开启内力能量池），以此法获取的内力生生不息。</p><p>此后，修习者将得到内力修行之法，每经历一场影片获得2点内功修为，内功修为可助修习者练就：</p><p>*内息循环：修习者的内力构成大周天循环，可以内力调息代替正常呼吸，达成此法需消耗一点内功修为。<br> *天人辟谷：修习者的内功修为雄浑厚重，可代替正常饮食维持身体活力，达成此法需消耗一点内功修为。<br> *观星神意：修习者的内力细致如发，可代替正常休息调理意念及体魄，达成此法需消耗一点内功修为；在此基础上，再消耗一点内功修为可时此法更进一步，获得自适应短休的能力；在此基础上，再消耗三点内功修为可使此法臻至化境，获得自适应长休的能力。<br> *若火明眸：修习者的内力供养眼眸，使得其在黑暗中亦可视物，获得黑暗视觉，达成此法需消耗一点内功修为；在此基础上，再消耗三点内功修为可时此法更臻至化境，获得洞见鬼怪的灵感视觉之能。<br> *轻盈具足：修习者的内力供养双足，使得其在水面上亦可纵横，获得获得等同于基础移动速度的水面速度，但不可站立于水面，达成此法需消耗一点内功修为；在此基础上，再消耗一点内功修为可时此法更进一步，获得下蹲/伏地/攀爬（三选一）时可全速移动的能力；在此基础上，再消耗三点内功修为可使此法臻至化境，获得取消潜行行走速度限制的能力。<br> *强健体魄：修习者的内力贯通全身，使其体魄更为强大，任意提升1级生理属性，此功效需消耗2点内功修为，除非你已获得了所有其他内力修为的能力，否则这一词条需在其他方面每消耗1点内力修为才能选择一次。</p><p>此内功为奠基之法，不擅推动武技运转，故除为修习者之武技提供修习者本身的内力属性的加成外，不再提供额外加成。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',9)])])}const f=r(p,[["render",d]]);export{m as __pageData,f as default};
